query {
  contacts(first: 10) {
    totalCount
    pageInfo {
      hasNextPage
      endCursor
    }
    nodes {
      attributes { name value }
    }
  }
}

query ContactByIdAndEmail($id: String!, $email: String!) {
  contacts(
    filter: [{ and: [
      { field: "Unique ID", eq: $id }
      { field: "Email",    eq: $email }
    ]}]
  ) {
    nodes {
      attributes(
        selectByName: ["First Name", "Last Name", "Email", "Unique ID"]
      ) { name value }
    }
    totalCount
  }
}

mutation {
  createContacts(
    contactsInput: [{
      attributes: [
        { name: "Unique ID",  value: "USR-001" }
        { name: "Email",      value: "user@example.com" }
        { name: "First Name", value: "Jane" }
        { name: "Last Name",  value: "Doe" }
      ]
    }]
  ) {
    items { contactKey }
  }
}

mutation {
  updateContacts(
    updateContactInputs: [{
      key: "{{contactKey}}"
      to: {
        attributes: [
          { name: "Last Name", value: "Updated" }
        ]
      }
    }]
  ) {
    modifiedCount
  }
}

mutation {
  updateContacts(
    dataSetId: "{{dataSetId}}"
    updateContactInputs: [{
      contactId: "{{contactId}}"
      to: {
        attributes: [
          { name: "Last Name", value: "Updated" }
        ]
      }
    }]
  ) {
    modifiedCount
  }
}

mutation {
  deleteContacts(where: {
    keyList: ["{{contactKey}}"]
    deleteReason: RIGHT_TO_BE_FORGOTTEN
  }) {
    deletedCount
  }
}

mutation {
  deleteContacts(where: {
    contactIdList: ["{{contactId}}"]
    deleteReason: USER_REQUEST
  }) {
    deletedCount
  }
}

mutation {
  deleteContacts(where: {
    addressableList: [
      { field: "Email", eq: "user@example.com" }
    ]
    deleteReason: USER_REQUEST
  }) {
    deletedCount
  }
}

mutation ($importInput: ImportInput!) {
  createImportJob(importInput: $importInput) {
    id
  }
}

graphql.variables:
{
  "importInput": {
    "jobName": "Contact Import",
    "importType": "ADD_UPDATE",
    "createSegment": false,
    "fileFormat": "DELIMITED",
    "delimiter": ",",
    "skipFirstRow": true,
    "fileLocation": {
      "type": "SFTP",
      "filename": "contacts.csv",
      "folder": "contacts"
    },
    "consent": {
      "channels": {
        "channel": "EMAIL",
        "status": "OPT_IN_UNVERIFIED"
      }
    },
    "mappings": [
      { "columnIndex": 1, "attributeName": "Contact Key" },
      { "columnIndex": 2, "attributeName": "Email" },
      { "columnIndex": 3, "attributeName": "First Name" },
      { "columnIndex": 4, "attributeName": "Last Name" }
    ]
  }
}

graphql.query:
{
  dataJob(id: "{{jobId}}") {
    id
    name
    type
    status
    startedAt
    endedAt
    errors { code message }
  }
}

{
  referenceSetRecords(
    dataSetId: "{{refSetId}}"
    first: 10
  ) {
    nodes {
      dataSetId
      attributes { name value }
    }
    pageInfo { hasNextPage endCursor }
  }
}

mutation {
  addReferenceSetAssociation(dataSetAssociation: {
    to:   "{{dataSetId}}"
    from: "{{refSetId}}"
    mappings: [{ to: "contactId", from: "contactId" }]
  }) {
    to   { dataSetId name }
    from { dataSetId name }
  }
}

mutation {
  deleteReferenceSetAssociation(
    to:   "{{dataSetId}}"
    from: "{{refSetId}}"
  ) {
    to   { dataSetId }
    from { dataSetId }
  }
}

{
  activityEvents(first: 10) {
    nodes {
      eventId
      eventCategory
      eventType
      eventDate
      contactId
      dataSetId
    }
    pageInfo { hasNextPage endCursor }
  }
}

{
  consentEvents(first: 10) {
    nodes {
      eventId
      eventCategory
      eventType
      eventDate
      contactId
      consentGroupId
      channel
      status
    }
    pageInfo { hasNextPage endCursor }
  }
}

query {
  products(first: 10) {
    nodes {
      attributes { name value type }
    }
    pageInfo { hasNextPage endCursor }
  }
}

query {
  products(filter: { field: "productId", eq: "{{productId}}" }) {
    nodes {
      attributes { name value type }
    }
  }
}

mutation {
  createProduct(
    productInput: {
      attributes: [
        { name: "productId",   value: "{{productId}}" }
        { name: "productName", value: "My New Product" }
        { name: "unitPrice",   value: 29.99 }
        { name: "currency",    value: "USD" }
      ]
    }
  ) {
    attributes { name value type }
  }
}

mutation {
  updateProduct(
    productId: "{{productId}}"
    updatedProduct: {
      attributes: [
        { name: "unitPrice",    value: 529.99 }
        { name: "availability", value: "In stock" }
      ]
    }
  ) {
    modifiedCount
  }
}

mutation {
  deleteProducts(productIds: ["{{productId}}"]) {
    deletedCount
  }
}

mutation {
  updateDataSet(
    where: { dataSetId: "{{catalogDataSetId}}" }
    to: {
      attributes: {
        create: [
          { name: "Available Offline", type: BOOLEAN }
          { name: "Region",            type: TEXT }
        ]
      }
    }
  ) {
    dataSetId
  }
}

mutation {
  createRightOfAccessJob(
    contactIds: ["{{contactId}}"]
    sendNotifications: true
  ) {
    jobId
  }
}

mutation {
  createRightToBeForgottenJob(
    contactIds: ["{{contactId}}"]
    sendNotifications: true
  ) {
    jobId
  }
}
